import 'package:dio/dio.dart'; import 'package:firebase_auth/firebase_auth.dart'; import '../utils/app_logger.dart'; class AuthInterceptor extends Interceptor { @override void onRequest(RequestOptions options, RequestInterceptorHandler handler) async { try { final token = await FirebaseAuth.instance.currentUser?.getIdToken(); if (token != null) options.headers['Authorization'] = 'Bearer $token'; } catch (e) { AppLogger.warning('Auth header: $e'); } handler.next(options); } @override void onError(DioException err, ErrorInterceptorHandler handler) { AppLogger.error('API Error: ${err.requestOptions.path}', err); handler.next(err); } }